+//! Unit tests for provider detection and session discovery (`ProviderRegistry`).
+
+use std::{
+    collections::HashMap,
+    path::{Path, PathBuf},
+};
+
+use casr::{
+    discovery::{DetectionResult, ProviderRegistry, SourceHint},
+    error::CasrError,
