+    let by_alias = registry
+        .find_by_alias("cod")
+        .expect("cod alias should resolve");
+    assert_eq!(by_alias.slug(), "codex");
+
+    let gmi_alias = registry
+        .find_by_alias("gmi")
+        .expect("gmi alias should resolve");
+    assert_eq!(gmi_alias.slug(), "gemini");
