+}
+
+fn tool_call_session() -> CanonicalSession {
+    CanonicalSession {
+        session_id: "golden-tools-001".to_string(),
+        provider_slug: "test".to_string(),
+        workspace: Some(PathBuf::from("/data/projects/golden_tools")),
